// MARK: - URL Validator (Core Security Layer)

class UniversalLinkValidator {
    
    /// Validates that the URL host is in our allowlist
    func validateHost(_ url: URL) -> Result<Void, PromoValidationError> {
        guard let host = url.host?.lowercased(),
              UniversalLinkConfig.allowedHosts.contains(host) else {
            let hostValue = url.host ?? "nil"
            return .failure(.invalidHost(hostValue))
        }
        return .success(())
    }
    
    /// Validates that the URL path matches an allowed route pattern
    func validatePath(_ url: URL) -> Result<Void, PromoValidationError> {
        let normalizedPath = normalizePath(url.path)
        guard UniversalLinkConfig.allowedPaths.contains(normalizedPath) else {
            return .failure(.invalidPath(normalizedPath))
        }
        return .success(())
    }
    
    /// Validates and extracts promo code from URL parameters
    func extractAndValidatePromoCode(_ url: URL) -> Result<PromoCode, PromoValidationError> {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let queryItems = components.queryItems else {
            return .failure(.missingPromoCode)
        }
        
        // Extract promo code
        guard let codeParam = queryItems.first(where: { $0.name == "code" })?.value,
              !codeParam.isEmpty else {
            return .failure(.missingPromoCode)
        }
        
        // Normalize: uppercase, trim whitespace
        let normalizedCode = codeParam.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        
        // Validate format with regex
        guard let regex = try? NSRegularExpression(pattern: UniversalLinkConfig.promoCodePattern),
              regex.firstMatch(in: normalizedCode, range: NSRange(normalizedCode.startIndex..., in: normalizedCode)) != nil else {
            return .failure(.invalidPromoCodeFormat(codeParam))
        }
        
        // Check against known valid campaigns
        guard UniversalLinkConfig.validPromoCampaigns.contains(normalizedCode) else {
            return .failure(.unrecognizedPromoCode(normalizedCode))
        }
        
        // Extract discount
        guard let discountParam = queryItems.first(where: { $0.name == "discount" })?.value,
              !discountParam.isEmpty else {
            return .failure(.missingDiscount)
        }
        
        // Validate discount is a valid integer
        guard let discountValue = Int(discountParam) else {
            return .failure(.invalidDiscountFormat(discountParam))
        }
        
        // Validate discount range
        guard discountValue >= UniversalLinkConfig.minDiscount,
              discountValue <= UniversalLinkConfig.maxDiscount else {
            return .failure(.discountOutOfRange(discountValue))
        }
        
        // Check for extra/suspicious parameters
        let allowedParamNames: Set<String> = ["code", "discount", "utm_source", "utm_medium", "utm_campaign"]
        let unexpectedParams = queryItems.filter { !allowedParamNames.contains($0.name) }
        if !unexpectedParams.isEmpty {
            SecurityLogger.shared.logSuspiciousActivity(
                "Unexpected parameters: \(unexpectedParams.map { $0.name })",
                url: url
            )
            // We still proceed but log the suspicious activity
        }
        
        let promo = PromoCode(code: normalizedCode, discountPercentage: discountValue, rawURL: url)
        return .success(promo)
    }
    
    /// Full validation pipeline
    func validateUniversalLink(_ url: URL) -> Result<PromoCode, PromoValidationError> {
        // Step 1: Validate host
        switch validateHost(url) {
        case .failure(let error):
            return .failure(error)
        case .success:
            break
        }
        
        // Step 2: Validate path
        switch validatePath(url) {
        case .failure(let error):
            return .failure(error)
        case .success:
            break
        }
        
        // Step 3: Validate and extract parameters
        return extractAndValidatePromoCode(url)
    }
    
    // MARK: - Private Helpers
    
    private func normalizePath(_ path: String) -> String {
        var normalized = path.lowercased()
        // Remove trailing slash
        if normalized.hasSuffix("/") && normalized.count > 1 {
            normalized = String(normalized.dropLast())
        }
        // Prevent path traversal
        normalized = normalized.replacingOccurrences(of: "..", with: "")
        normalized = normalized.replacingOccurrences(of: "//", with: "/")
        return normalized
    }
}

// MARK: - Promo Service (Business Logic Layer)

protocol PromoServiceProtocol {
    func validatePromoWithServer(promo: PromoCode, completion: @escaping (Result<Bool, PromoValidationError>) -> Void)
    func applyPromoToAccount(promo: PromoCode, account: UserAccount, completion: @escaping (Result<Void, PromoValidationError>) -> Void)
}

class PromoService: PromoServiceProtocol {
    
    private let validator = UniversalLinkValidator()
    private let logger = SecurityLogger.shared
    
    /// Simulates server-side validation of the promo code
    func validatePromoWithServer(promo: PromoCode, completion: @escaping (Result<Bool, PromoValidationError>) -> Void) {
        // In production, this would be an actual API call:
        // POST /api/v1/promo/validate { code: "XYZ", discount: 50 }
        // The server would verify:
        // - The promo code exists in the database
        // - The discount matches what's stored server-side (not just what the URL says)
        // - The promo hasn't expired
        // - Usage limits haven't been exceeded
        
        logger.logInfo("Validating promo \(promo.code) with server...")
        
        // Simulate network delay
        DispatchQueue.global().asyncAfter(deadline: .now() + 0.5) {
            // Simulate server response - in production, ALWAYS verify discount server-side
            // Never trust the discount value from the URL alone
            let serverApprovedCodes: [String: Int] = [
                "SUMMER2024": 20,
                "WELCOME10": 10,
                "VIP50": 50,
                "FLASH30": 30,
                "HOLIDAY25": 25,
                "NEWUSER20": 20,
                "LOYALTY15": 15,
                "REFER10": 10,
                "BIRTHDAY50": 50,
                "SPECIAL40": 40
            ]
            
            guard let serverDiscount = serverApprovedCodes[promo.code] else {
                completion(.failure(.serverValidationFailed("Code not found on server")))
                return
            }
            
            // CRITICAL: Verify the discount in the URL matches server-side value
            // This prevents URL parameter tampering (e.g., changing discount=50 to discount=99)
            guard serverDiscount == promo.discountPercentage else {
                self.logger.logSuspiciousActivity(
                    "Discount mismatch! URL says \(promo.discountPercentage)% but server says \(serverDiscount)% for code \(promo.code)",
                    url: promo.rawURL
                )
                completion(.failure(.serverValidationFailed("Discount value mismatch - possible tampering detected")))
                return
            }
            
            completion(.success(true))
        }
    }
    
    /// Applies a validated promo code to a user account
    func applyPromoToAccount(promo: PromoCode, account: UserAccount, completion: @escaping (Result<Void, PromoValidationError>) -> Void) {
        
        // Authorization check: user must be authenticated
        guard account.isAuthenticated else {
            logger.logValidationFailure(.userNotAuthenticated, url: promo.rawURL)
            completion(.failure(.userNotAuthenticated))
            return
        }
        
        // Check if promo already applied
        guard !account.appliedPromoCodes.contains(promo.code) else {
            completion(.failure(.promoAlreadyApplied(promo.code)))
            return
        }
        
        // Server-side validation first
        validatePromoWithServer(promo: promo) { [weak self] result in
            switch result {
            case .success:
                // Apply the discount
                account.appliedPromoCodes.append(promo.code)
                account.currentDiscount = max(account.currentDiscount, promo.discountPercentage)
                
                self?.logger.logPromoApplied(promo, userId: account.userId)
                completion(.success(()))
                
            case .failure(let error):
                self?.logger.logValidationFailure(error, url: promo.rawURL)
                completion(.failure(error))
            }
        }
    }
}

// MARK: - Rate Limiter

class RateLimiter {
    private var attempts: [(date: Date, url: String)] = []
    private let maxAttempts: Int
    private let windowSeconds: TimeInterval
    
    init(maxAttempts: Int = 10, windowSeconds: TimeInterval = 60) {
        self.maxAttempts = maxAttempts
        self.windowSeconds = windowSeconds
    }
    
    func shouldAllow(url: URL) -> Bool {
        let now = Date()
        // Remove old entries
        attempts.removeAll { now.timeIntervalSince($0.date) > windowSeconds }
        
        if attempts.count >= maxAttempts {
            SecurityLogger.shared.logSuspiciousActivity("Rate limit exceeded", url: url)
            return false
        }
        
        attempts.append((date: now, url: url.absoluteString))
        return true
    }
}

// MARK: - Universal Link Handler

class UniversalLinkHandler {
    
    private let validator = UniversalLinkValidator()
    private let promoService: PromoServiceProtocol
    private let rateLimiter = RateLimiter()
    private let logger = SecurityLogger.shared
    
    weak var delegate: UniversalLinkHandlerDelegate?
    
    init(promoService: PromoServiceProtocol = PromoService()) {
        self.promoService = promoService
    }
    
    /// Main entry point for handling universal links
    func handleUniversalLink(_ url: URL, userAccount: UserAccount?) -> Bool {
        logger.logInfo("Received universal link: \(url.absoluteString)")
        
        // Rate limiting
        guard rateLimiter.shouldAllow(url: url) else {
            delegate?.didFailToApplyPromo(error: .serverValidationFailed("Too many attempts. Please try again later."))
            return false
        }
        
        // Validate the URL through our security pipeline
        let validationResult = validator.validateUniversalLink(url)
        
        switch validationResult {
        case .failure(let error):
            logger.logValidationFailure(error, url: url)
            delegate?.didFailToApplyPromo(error: error)
            return false
            
        case .success(let promo):
            logger.logInfo("URL validated successfully: \(promo.description)")
            
            // Authorization check
            guard let account = userAccount, account.isAuthenticated else {
                logger.logInfo("User not authenticated - storing promo for later application")
                delegate?.didRequireAuthentication(pendingPromo: promo)
                return true
            }
            
            // Apply promo through service layer (includes server validation)
            promoService.applyPromoToAccount(promo: promo, account: account) { [weak self] result in
                DispatchQueue.main.async {
                    switch result {
                    case .success:
                        self?.delegate?.didApplyPromo(promo, toAccount: account)
                    case .failure(let error):
                        self?.delegate?.didFailToApplyPromo(error: error)
                    }
                }
            }
            
            return true
        }
    }
}

// MARK: - Delegate Protocol

protocol UniversalLinkHandlerDelegate: AnyObject {
    func didApplyPromo(_ promo: PromoCode, toAccount account: UserAccount)
    func didFailToApplyPromo(error: PromoValidationError)
    func didRequireAuthentication(pendingPromo: PromoCode)
}

