            testTamperButton.heightAnchor.constraint(equalToConstant: 50),
        ])
        
        return vc
    }
    
    @objc private func testPromoLink() {
        // Valid promo link
        if let url = URL(string: "https://myapp.com/promo?code=VIP50&discount=50") {
            handleIncomingURL(url)
        }
    }
    
    @objc private func testInvalidLink() {
        // Invalid host
        if let url = URL(string: "https://evil.com/promo?code=HACK&discount=99") {
            handleIncomingURL(url)
        }
    }
    
    @objc private func testTamperedLink() {
        // Valid code but tampered discount (SUMMER2024 should be 20%, not 99%)
        if let url = URL(string: "https://myapp.com/promo?code=SUMMER2024&discount=99") {
            handleIncomingURL(url)
        }
    }
    
    // MARK: - UniversalLinkHandlerDelegate
    
    func didApplyPromo(_ promo: PromoCode, toAccount account: UserAccount) {
        let promoVC = PromoViewController()
        promoVC.promoCode = promo
        promoVC.isSuccess = true
        navigationController?.pushViewController(promoVC, animated: true)
    }
    
    func didFailToApplyPromo(error: PromoValidationError) {
        let promoVC = PromoViewController()
        promoVC.isSuccess = false
        promoVC.errorMessage = error.description
        navigationController?.pushViewController(promoVC, animated: true)
    }
    
    func didRequireAuthentication(pendingPromo: PromoCode) {
        self.pendingPromo = pendingPromo
        
        let loginVC = LoginPromptViewController()
        loginVC.pendingPromo = pendingPromo
        loginVC.onLoginComplete = { [weak self] account in
            self?.currentUser = account
            // Re-process the pending promo after authentication
            _ = self?.linkHandler.handleUniversalLink(pendingPromo.rawURL, userAccount: account)
            self?.navigationController?.popViewController(animated: true)
        }
        navigationController?.pushViewController(loginVC, animated: true)
    }
}

// MARK: - App Delegate

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    func application(_ application: UIApplication, configurationForConnecting connectingSceneSession: UISceneSession, options: UIScene.ConnectionOptions) -> UISceneConfiguration {
        let config = UISceneConfiguration(name: "Default Configuration", sessionRole: connectingSceneSession.role)
        config.delegateClass = SceneDelegate.self
        return config
    }
    
    // Handle universal links for iOS 12 and below (fallback)
    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let _ = userActivity.webpageURL else {
            return false
        }
        // Forwarded to SceneDelegate in iOS 13+
        return true
    }
}